 1→import type { SemanticReviewAnnotation } from "../../lib/ipc";
 2→import type { DiffComment } from "./comments";
 3→
 4→export function toSemanticReviewDiffComments(
 5→  annotations: SemanticReviewAnnotation[],
 6→  reviewRunId: string
 7→): DiffComment[] {
 8→  return annotations.map((annotation) => ({
 9→    id: crypto.randomUUID(),
10→    filePath: annotation.file_path,
11→    lineKey: annotation.line_key,
12→    lineKind: annotation.line_kind,
13→    lineContent: annotation.line_content,
14→    lineNumber: annotation.line_number,
15→    comment: formatSemanticReviewComment(annotation),
16→    createdAt: Date.now(),
17→    source: "semantic_review",
18→    readonly: true,
19→    reviewRunId,
20→  }));
21→}
22→
23→function formatSemanticReviewComment(annotation: SemanticReviewAnnotation): string {
24→  const parts = [annotation.summary.trim()];
25→  if (annotation.rationale?.trim()) {
26→    parts.push(annotation.rationale.trim());
27→  }
28→  return parts.join("\n\n");
29→}
