  1→import { useEffect, useMemo, useState } from "react";
  2→import {
  3→  FileCode,
  4→  FilePlus,
  5→  FileMinus,
  6→  ChevronDown,
  7→  ChevronRight,
  8→  Loader2,
  9→  GitCommit,
 10→  MessageSquarePlus,
 11→  Sparkles,
 12→} from "lucide-react";
 13→import { useMutation } from "@tanstack/react-query";
 14→import { useDiffQuery, useBranchDiffQuery } from "../../hooks/use-tauri-query";
 15→import { useDiffComments } from "../../hooks/use-diff-comments";
 16→import type { DiffComment } from "../../hooks/use-diff-comments";
 17→import {
 18→  runCheckpointSemanticReview,
 19→  type CheckpointSummary,
 20→  type FileDiff,
 21→  type DiffLine as DiffLineType,
 22→} from "../../lib/ipc";
 23→import { getDiffLineTextColor } from "./colors";
 24→import { getInitiallyExpandedFilePaths } from "./file-expansion";
 25→import { DiffCommentBox } from "./DiffCommentBox";
 26→import { ReviewBar } from "./ReviewBar";
 27→import { toSemanticReviewDiffComments } from "./semantic-review";
 28→import { canWriteDiffComments, getVisibleDiffComments } from "./comments";
 29→
 30→interface DiffViewProps {
 31→  repoPath: string;
 32→  checkpoint: CheckpointSummary | null;
 33→  onSendToAgent?: (agent: string, prompt: string) => void;
 34→}
 35→
 36→const STATUS_CONFIG = {
 37→  added: { icon: FilePlus, color: "text-green", bg: "bg-green-bg", label: "Added" },
 38→  deleted: { icon: FileMinus, color: "text-red", bg: "bg-red-bg", label: "Deleted" },
 39→  modified: { icon: FileCode, color: "text-yellow", bg: "bg-yellow-bg", label: "Modified" },
 40→} as const;
 41→
 42→function makeLineKey(
 43→  filePath: string,
 44→  line: DiffLineType
 45→): string {
 46→  return `${filePath}:${line.old_lineno ?? ""}:${line.new_lineno ?? ""}`;
 47→}
 48→
 49→function getLineNumber(line: DiffLineType): number {
 50→  if (line.kind === "delete") return line.old_lineno ?? 0;
 51→  return line.new_lineno ?? line.old_lineno ?? 0;
 52→}
 53→
 54→function DiffLineRow({
 55→  line,
 56→  lineKey,
 57→  commentCount,
 58→  commentsEnabled,
 59→  onCommentClick,
 60→}: {
 61→  line: DiffLineType;
 62→  lineKey: string;
 63→  commentCount: number;
 64→  commentsEnabled: boolean;
 65→  onCommentClick: (
 66→    lineKey: string,
 67→    lineContent: string,
 68→    lineNumber: number,
 69→    lineKind: "add" | "delete" | "context"
 70→  ) => void;
 71→}) {
 72→  const isAdd = line.kind === "add";
 73→  const isDel = line.kind === "delete";
 74→  const textColor = getDiffLineTextColor(line.kind);
 75→
 76→  return (
 77→    <div
 78→      className="group/line relative flex font-mono text-xs leading-[22px]"
 79→      style={{
 80→        backgroundColor: isAdd
 81→          ? "var(--color-diff-add-bg)"
 82→          : isDel
 83→            ? "var(--color-diff-delete-bg)"
 84→            : "transparent",
 85→      }}
 86→    >
 87→      {/* Comment gutter — click target */}
 88→      {commentsEnabled && (
 89→        <button
 90→          onClick={() =>
 91→            onCommentClick(lineKey, line.content, getLineNumber(line), line.kind)
 92→          }
 93→          className="absolute left-0 top-0 z-10 flex h-[22px] w-[18px] items-center justify-center opacity-0 transition-opacity group-hover/line:opacity-100"
 94→          style={{ color: "var(--color-accent-fg)" }}
 95→          title="Add comment"
 96→        >
 97→          <MessageSquarePlus size={12} />
 98→        </button>
 99→      )}
100→
101→      {/* Old line number */}
102→      <span
103→        className="inline-block w-[50px] shrink-0 select-none border-r px-2 text-right text-[11px] leading-[22px] text-fg-subtle"
104→        style={{
105→          borderColor: "var(--color-border-subtle)",
106→          backgroundColor: isDel
107→            ? "var(--color-diff-delete-gutter)"
108→            : isAdd
109→              ? "var(--color-diff-add-gutter)"
110→              : "transparent",
111→        }}
112→      >
113→        {line.old_lineno ?? ""}
114→      </span>
115→      {/* New line number */}
116→      <span
117→        className="inline-block w-[50px] shrink-0 select-none border-r px-2 text-right text-[11px] leading-[22px] text-fg-subtle"
118→        style={{
119→          borderColor: "var(--color-border-subtle)",
120→          backgroundColor: isAdd
121→            ? "var(--color-diff-add-gutter)"
122→            : isDel
123→              ? "var(--color-diff-delete-gutter)"
124→              : "transparent",
125→        }}
126→      >
127→        {line.new_lineno ?? ""}
128→      </span>
129→      {/* +/- indicator */}
130→      <span
131→        className="inline-block w-5 shrink-0 select-none text-center text-[11px] leading-[22px]"
132→        style={{ color: isAdd || isDel ? textColor : "var(--color-fg-faint)" }}
133→      >
134→        {isAdd ? "+" : isDel ? "-" : " "}
135→      </span>
136→      {/* Code content */}
137→      <pre
138→        className="min-w-0 flex-1 whitespace-pre-wrap break-all pr-4"
139→        style={{ color: textColor }}
140→      >
141→        {line.content}
142→      </pre>
143→
144→      {/* Comment count badge */}
145→      {commentCount > 0 && (
146→        <span
147→          className="mr-2 mt-[3px] flex h-4 min-w-[16px] shrink-0 items-center justify-center rounded-full px-1 text-[10px] font-medium text-white"
148→          style={{ backgroundColor: "var(--color-accent)" }}
149→        >
150→          {commentCount}
151→        </span>
152→      )}
153→    </div>
154→  );
155→}
156→
157→function FileEntry({
158→  file,
159→  defaultExpanded,
160→  commentsByLine,
161→  commentsEnabled,
162→  activeCommentLine,
163→  onCommentClick,
164→  onSaveComment,
165→  onUpdateComment,
166→  onDeleteComment,
167→  onCloseComment,
168→}: {
169→  file: FileDiff;
170→  defaultExpanded: boolean;
171→  commentsByLine: Map<string, DiffComment[]>;
172→  commentsEnabled: boolean;
173→  activeCommentLine: string | null;
174→  onCommentClick: (
175→    lineKey: string,
176→    lineContent: string,
177→    lineNumber: number,
178→    lineKind: "add" | "delete" | "context"
179→  ) => void;
180→  onSaveComment: (
181→    filePath: string,
182→    lineKey: string,
183→    lineKind: "add" | "delete" | "context",
184→    lineContent: string,
185→    lineNumber: number,
186→    comment: string
187→  ) => void;
188→  onUpdateComment: (id: string, comment: string) => void;
189→  onDeleteComment: (id: string) => void;
190→  onCloseComment: () => void;
191→}) {
192→  const [expanded, setExpanded] = useState(defaultExpanded);
193→  const config = STATUS_CONFIG[file.status] || STATUS_CONFIG.modified;
194→  const Icon = config.icon;
195→
196→  const additions = file.hunks.reduce(
197→    (sum, h) => sum + h.lines.filter((l) => l.kind === "add").length,
198→    0
199→  );
200→  const deletions = file.hunks.reduce(
201→    (sum, h) => sum + h.lines.filter((l) => l.kind === "delete").length,
202→    0
203→  );
204→
205→  // Count comments for this file
206→  const fileCommentCount = Array.from(commentsByLine.entries()).reduce(
207→    (sum, [key, cs]) => (key.startsWith(file.path + ":") ? sum + cs.length : sum),
208→    0
209→  );
210→
211→  return (
212→    <div className="mb-2 overflow-hidden rounded-lg border border-border-subtle">
213→      {/* File header */}
214→      <button
215→        onClick={() => setExpanded(!expanded)}
216→        className="flex w-full items-center gap-2 bg-bg-overlay px-3 py-2 text-left transition-colors hover:bg-bg-hover"
217→      >
218→        {expanded ? (
219→          <ChevronDown size={14} className="shrink-0 text-fg-subtle" />
220→        ) : (
221→          <ChevronRight size={14} className="shrink-0 text-fg-subtle" />
222→        )}
223→        <Icon size={14} className={`shrink-0 ${config.color}`} />
224→        <span className="min-w-0 flex-1 truncate font-mono text-xs text-fg">
225→          {file.path}
226→        </span>
227→        {fileCommentCount > 0 && (
228→          <span
229→            className="flex h-4 min-w-[16px] shrink-0 items-center justify-center rounded-full px-1 text-[10px] font-medium text-white"
230→            style={{ backgroundColor: "var(--color-accent)" }}
231→          >
232→            {fileCommentCount}
233→          </span>
234→        )}
235→        <span className={`shrink-0 rounded px-1.5 py-0.5 text-[10px] font-medium ${config.bg} ${config.color}`}>
236→          {config.label}
237→        </span>
238→        {additions > 0 && (
239→          <span className="shrink-0 font-mono text-[11px] text-green">
240→            +{additions}
241→          </span>
242→        )}
243→        {deletions > 0 && (
244→          <span className="shrink-0 font-mono text-[11px] text-red">
245→            -{deletions}
246→          </span>
247→        )}
248→      </button>
249→
250→      {/* Diff hunks */}
251→      {expanded && (
252→        <div className="overflow-x-auto border-t border-border-subtle bg-bg">
253→          {file.hunks.map((hunk, hi) => (
254→            <div key={hi}>
255→              {/* Hunk header */}
256→              <div
257→                className="border-b px-4 py-1 font-mono text-[11px]"
258→                style={{
259→                  backgroundColor: "var(--color-diff-hunk-bg)",
260→                  borderColor: "var(--color-border-subtle)",
261→                  color: "var(--color-accent-fg)",
262→                }}
263→              >
264→                {hunk.header.trim()}
265→              </div>
266→              {/* Lines */}
267→              <div>
268→                {hunk.lines.map((line, li) => {
269→                  const lineKey = makeLineKey(file.path, line);
270→                  const lineComments = commentsByLine.get(lineKey) ?? [];
271→                  const isActive = activeCommentLine === lineKey;
272→
273→                  return (
274→                    <div key={li}>
275→                      <DiffLineRow
276→                        line={line}
277→                        lineKey={lineKey}
278→                        commentCount={lineComments.length}
279→                        commentsEnabled={commentsEnabled}
280→                        onCommentClick={onCommentClick}
281→                      />
282→                      {/* Show comment box if line has comments or is active target */}
283→                      {(lineComments.length > 0 || isActive) && (
284→                        <DiffCommentBox
285→                          comments={lineComments}
286→                          commentsEnabled={commentsEnabled}
287→                          filePath={file.path}
288→                          lineKey={lineKey}
289→                          lineKind={line.kind}
290→                          lineContent={line.content}
291→                          lineNumber={getLineNumber(line)}
292→                          onSave={onSaveComment}
293→                          onUpdate={onUpdateComment}
294→                          onDelete={onDeleteComment}
295→                          onClose={onCloseComment}
296→                        />
297→                      )}
298→                    </div>
299→                  );
300→                })}
301→              </div>
302→            </div>
303→          ))}
304→          {file.hunks.length === 0 && (
305→            <div className="px-4 py-3 text-xs text-fg-subtle">
306→              Binary file or no textual changes
307→            </div>
308→          )}
309→        </div>
310→      )}
311→    </div>
312→  );
313→}
314→
315→function DiffFileList({
316→  files,
317→  summaryLabel,
318→  summaryDetail,
319→  storageKey,
320→  context,
321→  onSendToAgent,
322→  semanticReviewContext,
323→}: {
324→  files: FileDiff[];
325→  summaryLabel: string;
326→  summaryDetail?: string;
327→  storageKey: string;
328→  context: { commitSha?: string; branch?: string };
329→  onSendToAgent?: (agent: string, prompt: string) => void;
330→  semanticReviewContext?: {
331→    repoPath: string;
332→    checkpointId: string;
333→    commitSha: string;
334→  };
335→}) {
336→  const initiallyExpandedFiles = getInitiallyExpandedFilePaths(files);
337→  const {
338→    comments,
339→    addComment,
340→    updateComment,
341→    deleteComment,
342→    clearManualComments,
343→    replaceSemanticReviewComments,
344→  } = useDiffComments(storageKey);
345→
346→  const [activeCommentLine, setActiveCommentLine] = useState<string | null>(
347→    null
348→  );
349→  const [semanticReviewNotice, setSemanticReviewNotice] = useState<string | null>(
350→    null
351→  );
352→
353→  const commentsEnabled = canWriteDiffComments(Boolean(semanticReviewContext));
354→  const visibleComments = useMemo(
355→    () => getVisibleDiffComments(comments, !commentsEnabled),
356→    [comments, commentsEnabled]
357→  );
358→  const visibleCommentsByLine = useMemo(() => {
359→    const map = new Map<string, DiffComment[]>();
360→    for (const comment of visibleComments) {
361→      const existing = map.get(comment.lineKey);
362→      if (existing) {
363→        existing.push(comment);
364→      } else {
365→        map.set(comment.lineKey, [comment]);
366→      }
367→    }
368→    return map;
369→  }, [visibleComments]);
370→
371→  const semanticReviewMutation = useMutation({
372→    mutationFn: async () => {
373→      if (!semanticReviewContext) {
374→        throw new Error("Semantic review is only available for checkpoint diffs");
375→      }
376→      return runCheckpointSemanticReview(
377→        semanticReviewContext.repoPath,
378→        semanticReviewContext.checkpointId,
379→        semanticReviewContext.commitSha
380→      );
381→    },
382→    onSuccess: (result) => {
383→      replaceSemanticReviewComments(
384→        toSemanticReviewDiffComments(result.annotations, result.review_run_id)
385→      );
386→      setSemanticReviewNotice(
387→        result.annotations.length > 0
388→          ? `Semantic review added ${result.annotations.length} comment${result.annotations.length === 1 ? "" : "s"}.`
389→          : "Semantic review found no high-signal changes to annotate."
390→      );
391→    },
392→    onError: (error) => {
393→      setSemanticReviewNotice(
394→        error instanceof Error ? error.message : "Semantic review failed"
395→      );
396→    },
397→  });
398→
399→  useEffect(() => {
400→    setActiveCommentLine(null);
401→    setSemanticReviewNotice(null);
402→    semanticReviewMutation.reset();
403→  }, [semanticReviewMutation.reset, storageKey]);
404→
405→  const totalAdditions = files.reduce(
406→    (sum, f) =>
407→      sum + f.hunks.reduce((s, h) => s + h.lines.filter((l) => l.kind === "add").length, 0),
408→    0
409→  );
410→  const totalDeletions = files.reduce(
411→    (sum, f) =>
412→      sum + f.hunks.reduce((s, h) => s + h.lines.filter((l) => l.kind === "delete").length, 0),
413→    0
414→  );
415→
416→  function handleCommentClick(
417→    lineKey: string,
418→    _lineContent: string,
419→    _lineNumber: number,
420→    _lineKind: "add" | "delete" | "context"
421→  ) {
422→    if (!commentsEnabled) return;
423→    setActiveCommentLine((prev) => (prev === lineKey ? null : lineKey));
424→  }
425→
426→  function handleSaveComment(
427→    filePath: string,
428→    lineKey: string,
429→    lineKind: "add" | "delete" | "context",
430→    lineContent: string,
431→    lineNumber: number,
432→    comment: string
433→  ) {
434→    addComment(filePath, lineKey, lineKind, lineContent, lineNumber, comment);
435→    // Keep the comment box open after saving
436→  }
437→
438→  function handleCloseComment() {
439→    setActiveCommentLine(null);
440→  }
441→
442→  function handleSendToAgent(agent: string, prompt: string) {
443→    onSendToAgent?.(agent, prompt);
444→  }
445→
446→  return (
447→    <div className="relative flex flex-1 flex-col">
448→      <div className="flex-1 overflow-y-auto px-5 py-4">
449→        <div className="mb-4 flex items-center gap-3 rounded-lg border border-border-subtle bg-bg-overlay px-4 py-3">
450→          <GitCommit size={14} className="text-fg-subtle" />
451→          <span className="font-mono text-xs text-fg-muted">{summaryLabel}</span>
452→          {summaryDetail && (
453→            <span className="text-xs text-fg-muted">{summaryDetail}</span>
454→          )}
455→          <div className="ml-auto flex items-center gap-3 text-xs">
456→            <span className="text-fg-subtle">{files.length} files</span>
457→            {totalAdditions > 0 && (
458→              <span className="font-mono text-green">+{totalAdditions}</span>
459→            )}
460→            {totalDeletions > 0 && (
461→              <span className="font-mono text-red">-{totalDeletions}</span>
462→            )}
463→            {semanticReviewContext && (
464→              <button
465→                onClick={() => {
466→                  setSemanticReviewNotice(null);
467→                  semanticReviewMutation.mutate();
468→                }}
469→                disabled={semanticReviewMutation.isPending}
470→                className="flex items-center gap-1.5 rounded border border-border-subtle px-2.5 py-1 text-[11px] text-fg-subtle transition-colors hover:border-accent hover:text-fg disabled:cursor-not-allowed disabled:opacity-50"
471→              >
472→                {semanticReviewMutation.isPending ? (
473→                  <Loader2 size={11} className="animate-spin" />
474→                ) : (
475→                  <Sparkles size={11} />
476→                )}
477→                Semantic Review
478→              </button>
479→            )}
480→          </div>
481→        </div>
482→        {semanticReviewNotice && (
483→          <div className="mb-4 rounded-lg border border-border-subtle bg-bg-overlay px-4 py-2 text-xs text-fg-muted">
484→            {semanticReviewNotice}
485→          </div>
486→        )}
487→        {files.map((file) => (
488→          <FileEntry
489→            key={file.path}
490→            file={file}
491→            defaultExpanded={initiallyExpandedFiles.has(file.path)}
492→            commentsByLine={visibleCommentsByLine}
493→            commentsEnabled={commentsEnabled}
494→            activeCommentLine={activeCommentLine}
495→            onCommentClick={handleCommentClick}
496→            onSaveComment={handleSaveComment}
497→            onUpdateComment={updateComment}
498→            onDeleteComment={deleteComment}
499→            onCloseComment={handleCloseComment}
500→          />
501→        ))}
502→      </div>
503→
504→      {/* Review bar */}
505→      <ReviewBar
506→        comments={visibleComments.filter((comment) => comment.source === "manual")}
507→        context={context}
508→        onSendToAgent={handleSendToAgent}
509→        onClearAll={clearManualComments}
510→      />
511→    </div>
512→  );
513→}
514→
515→export function DiffView({ repoPath, checkpoint, onSendToAgent }: DiffViewProps) {
516→  const { data: files, isLoading, error } = useDiffQuery(
517→    repoPath,
518→    checkpoint?.commit_sha ?? ""
519→  );
520→
521→  if (!checkpoint) {
522→    return (
523→      <div className="flex items-center justify-center p-20 text-fg-subtle">
524→        Select a checkpoint to view its diff
525→      </div>
526→    );
527→  }
528→
529→  if (!checkpoint.commit_sha) {
530→    return (
531→      <div className="p-8">
532→        <div className="rounded-lg border border-border-subtle bg-bg-overlay p-6 text-center">
533→          <p className="text-sm text-fg-muted">No commit SHA available</p>
534→          <p className="mt-1 text-xs text-fg-subtle">
535→            This checkpoint's commit reference was not recorded
536→          </p>
537→          {checkpoint.files_touched.length > 0 && (
538→            <div className="mx-auto mt-4 max-w-md text-left">
539→              <p className="mb-2 text-[10px] font-semibold uppercase tracking-wider text-fg-subtle">
540→                Files touched
541→              </p>
542→              {checkpoint.files_touched.map((f) => (
543→                <div
544→                  key={f}
545→                  className="flex items-center gap-2 py-1 font-mono text-xs text-fg-muted"
546→                >
547→                  <FileCode size={12} className="shrink-0 text-fg-subtle" />
548→                  {f}
549→                </div>
550→              ))}
551→            </div>
552→          )}
553→        </div>
554→      </div>
555→    );
556→  }
557→
558→  if (isLoading) {
559→    return (
560→      <div className="flex items-center justify-center p-20">
561→        <Loader2 size={20} className="animate-spin text-fg-subtle" />
562→      </div>
563→    );
564→  }
565→
566→  if (error) {
567→    return (
568→      <div className="p-8">
569→        <div className="rounded-lg border border-border-subtle bg-bg-overlay p-6 text-center">
570→          <p className="text-sm text-fg-muted">Failed to load diff</p>
571→          <p className="mt-1 text-xs text-fg-subtle">
572→            {error instanceof Error ? error.message : "Unknown error"}
573→          </p>
574→        </div>
575→      </div>
576→    );
577→  }
578→
579→  if (!files || files.length === 0) {
580→    return (
581→      <div className="p-8">
582→        <div className="rounded-lg border border-border-subtle bg-bg-overlay p-6 text-center">
583→          <p className="text-sm text-fg-muted">No changes in this commit</p>
584→        </div>
585→      </div>
586→    );
587→  }
588→
589→  return (
590→    <DiffFileList
591→      files={files}
592→      summaryLabel={checkpoint.commit_sha.slice(0, 7)}
593→      summaryDetail={checkpoint.commit_message || "Untitled commit"}
594→      storageKey={`entire:diff-comments:${checkpoint.commit_sha}`}
595→      context={{ commitSha: checkpoint.commit_sha }}
596→      onSendToAgent={onSendToAgent}
597→      semanticReviewContext={{
598→        repoPath,
599→        checkpointId: checkpoint.checkpoint_id,
600→        commitSha: checkpoint.commit_sha,
601→      }}
602→    />
603→  );
604→}
