606→interface BranchDiffViewProps {
607→  repoPath: string;
608→  branch: string;
609→  onSendToAgent?: (agent: string, prompt: string) => void;
610→}
611→
612→export function BranchDiffView({ repoPath, branch, onSendToAgent }: BranchDiffViewProps) {
613→  const { data: files, isLoading, error } = useBranchDiffQuery(repoPath, branch);
614→
615→  if (isLoading) {
616→    return (
617→      <div className="flex items-center justify-center p-20">
618→        <Loader2 size={20} className="animate-spin text-fg-subtle" />
619→      </div>
620→    );
621→  }
622→
