 13→interface ReviewBarProps {
 14→  comments: DiffComment[];
 15→  context: { commitSha?: string; branch?: string };
 16→  onSendToAgent: (agent: string, prompt: string) => void;
 17→  onClearAll: () => void;
 18→}
 19→
 20→export function ReviewBar({
 21→  comments,
 22→  context,
 23→  onSendToAgent,
 24→  onClearAll,
 25→}: ReviewBarProps) {
 26→  const [expanded, setExpanded] = useState(false);
 27→  const [copied, setCopied] = useState(false);
 28→
 29→  if (comments.length === 0) return null;
 30→
 31→  const fileCount = new Set(comments.map((c) => c.filePath)).size;
 32→  const prompt = buildReviewPrompt(comments, context);
 33→
 34→  function handleCopy() {
 35→    navigator.clipboard.writeText(prompt);
 36→    setCopied(true);
 37→    setTimeout(() => setCopied(false), 2000);
 38→  }
 39→
 40→  function handleSend() {
 41→    onSendToAgent("claude-code", prompt);
 42→  }
 43→
 44→  // Group comments by file for expanded view
 45→  const byFile = new Map<string, DiffComment[]>();
 46→  for (const c of comments) {
 47→    const existing = byFile.get(c.filePath);
 48→    if (existing) existing.push(c);
 49→    else byFile.set(c.filePath, [c]);
 50→  }
 51→
 52→  return (
 53→    <div
 54→      className="sticky bottom-0 z-20 border-t"
 55→      style={{
 56→        borderColor: "var(--color-accent)",
 57→        backgroundColor: "var(--color-bg-raised)",
 58→      }}
 59→    >
 60→      {/* Expanded comment list */}
 61→      {expanded && (
 62→        <div className="max-h-[240px] overflow-y-auto border-b border-border-subtle px-4 py-3">
 63→          {[...byFile.entries()].map(([filePath, fileComments]) => (
 64→            <div key={filePath} className="mb-3 last:mb-0">
 65→              <p className="mb-1 font-mono text-[11px] font-medium text-accent-fg">
 66→                {filePath}
 67→              </p>
 68→              {fileComments
 69→                .sort((a, b) => a.lineNumber - b.lineNumber)
 70→                .map((c) => (
 71→                  <div
 72→                    key={c.id}
 73→                    className="ml-3 flex items-baseline gap-2 py-0.5"
 74→                  >
 75→                    <span className="shrink-0 font-mono text-[10px] text-fg-subtle">
 76→                      L{c.lineNumber}
 77→                    </span>
 78→                    <span className="text-xs text-fg-muted">{c.comment}</span>
 79→                  </div>
 80→                ))}
 81→            </div>
 82→          ))}
 83→        </div>
 84→      )}
 85→
 86→      {/* Bar */}
 87→      <div className="flex items-center gap-3 px-4 py-2">
 88→        <button
 89→          onClick={() => setExpanded(!expanded)}
 90→          className="flex items-center gap-1.5 text-fg-muted transition-colors hover:text-fg"
 91→        >
 92→          <MessageSquare size={14} style={{ color: "var(--color-accent-fg)" }} />
 93→          <span className="text-xs font-medium">
 94→            {comments.length} comment{comments.length !== 1 ? "s" : ""}{" "}
 95→            <span className="font-normal text-fg-subtle">
 96→              across {fileCount} file{fileCount !== 1 ? "s" : ""}
 97→            </span>
 98→          </span>
 99→          {expanded ? <ChevronDown size={12} /> : <ChevronUp size={12} />}
100→        </button>
101→
102→        <div className="ml-auto flex items-center gap-2">
103→          {/* Copy Prompt */}
104→          <button
105→            onClick={handleCopy}
106→            className="flex items-center gap-1 rounded border border-border-subtle px-2.5 py-1 text-[11px] text-fg-subtle transition-colors hover:border-fg-subtle hover:text-fg"
107→          >
108→            <Clipboard size={11} />
109→            {copied ? "Copied!" : "Copy Prompt"}
110→          </button>
111→
112→          {/* Clear All */}
113→          <button
114→            onClick={onClearAll}
115→            className="flex items-center gap-1 rounded px-2 py-1 text-[11px] text-fg-subtle transition-colors hover:text-red"
116→            title="Clear all comments"
117→          >
118→            <Trash2 size={11} />
119→          </button>
120→
121→          {/* Send to Agent */}
122→          <button
123→            onClick={handleSend}
124→            className="flex items-center gap-1.5 rounded px-3 py-1 text-[11px] font-medium text-white transition-colors hover:opacity-90"
125→            style={{ backgroundColor: "var(--color-accent)" }}
126→          >
127→            <Send size={11} />
128→            Send to Agent
129→          </button>
130→        </div>
131→      </div>
132→    </div>
133→  );
134→}
