 1→import type { DiffComment } from "../../hooks/use-diff-comments";
 2→
 3→const KIND_LABEL: Record<string, string> = {
 4→  add: "addition",
 5→  delete: "deletion",
 6→  context: "context",
 7→};
 8→
 9→export function buildReviewPrompt(
10→  comments: DiffComment[],
11→  context: { commitSha?: string; branch?: string }
12→): string {
13→  if (comments.length === 0) return "";
14→
15→  const lines: string[] = [];
16→  lines.push("Please make the following changes based on my code review:");
17→  lines.push("");
18→
19→  if (context.commitSha) {
20→    lines.push(`> Reviewing commit ${context.commitSha.slice(0, 7)}`);
21→    lines.push("");
22→  } else if (context.branch) {
23→    lines.push(`> Reviewing branch "${context.branch}"`);
24→    lines.push("");
25→  }
26→
27→  // Group by file
28→  const byFile = new Map<string, DiffComment[]>();
29→  for (const c of comments) {
30→    const existing = byFile.get(c.filePath);
31→    if (existing) {
32→      existing.push(c);
33→    } else {
34→      byFile.set(c.filePath, [c]);
35→    }
36→  }
37→
38→  for (const [filePath, fileComments] of byFile) {
39→    lines.push(`## ${filePath}`);
40→    lines.push("");
41→
42→    // Sort by line number
43→    const sorted = [...fileComments].sort((a, b) => a.lineNumber - b.lineNumber);
44→
45→    for (const c of sorted) {
46→      const kindLabel = KIND_LABEL[c.lineKind] || c.lineKind;
47→      const contentPreview = c.lineContent.trim();
48→      lines.push(
49→        `### Line ${c.lineNumber} (${kindLabel}): \`${contentPreview}\``
50→      );
51→      lines.push(c.comment);
52→      lines.push("");
53→    }
54→  }
55→
56→  return lines.join("\n").trimEnd();
57→}
