  8→export type { DiffComment } from "../features/diff/comments";
  9→
 10→function loadComments(storageKey: string): DiffComment[] {
 11→  try {
 12→    const raw = localStorage.getItem(storageKey);
 13→    return raw ? JSON.parse(raw).map(normalizeComment) : [];
 14→  } catch {
 15→    return [];
 16→  }
 17→}
 18→
 19→function normalizeComment(comment: DiffComment): DiffComment {
 20→  return {
 21→    ...comment,
 22→    source: comment.source ?? "manual",
 23→    readonly: comment.readonly ?? false,
 24→  };
 25→}
 26→
 27→function saveComments(storageKey: string, comments: DiffComment[]) {
 28→  if (comments.length === 0) {
 29→    localStorage.removeItem(storageKey);
 30→  } else {
 31→    localStorage.setItem(storageKey, JSON.stringify(comments));
 32→  }
 33→}
 34→
 35→export function useDiffComments(storageKey: string) {
 36→  const [comments, setComments] = useState<DiffComment[]>(() =>
 37→    loadComments(storageKey)
 38→  );
 39→
 40→  // Re-load when storageKey changes
 41→  useEffect(() => {
 42→    setComments(loadComments(storageKey));
 43→  }, [storageKey]);
 44→
 45→  // Persist on every change
 46→  useEffect(() => {
 47→    saveComments(storageKey, comments);
 48→  }, [storageKey, comments]);
 49→
 50→  const commentsByLine = useMemo(() => {
 51→    const map = new Map<string, DiffComment[]>();
 52→    for (const c of comments) {
 53→      const existing = map.get(c.lineKey);
 54→      if (existing) {
 55→        existing.push(c);
 56→      } else {
 57→        map.set(c.lineKey, [c]);
 58→      }
 59→    }
 60→    return map;
 61→  }, [comments]);
 62→
 63→  const addComment = useCallback(
 64→    (
 65→      filePath: string,
 66→      lineKey: string,
 67→      lineKind: "add" | "delete" | "context",
 68→      lineContent: string,
 69→      lineNumber: number,
 70→      comment: string
 71→    ) => {
 72→      const newComment = createManualDiffComment({
 73→        filePath,
 74→        lineKey,
 75→        lineKind,
 76→        lineContent,
 77→        lineNumber,
 78→        comment,
 79→      });
 80→      setComments((prev) => [...prev, newComment]);
 81→    },
 82→    []
 83→  );
 84→
 85→  const updateComment = useCallback((id: string, comment: string) => {
 86→    setComments((prev) =>
 87→      prev.map((c) => (c.id === id ? { ...c, comment } : c))
 88→    );
 89→  }, []);
 90→
 91→  const deleteComment = useCallback((id: string) => {
 92→    setComments((prev) => prev.filter((c) => c.id !== id));
 93→  }, []);
 94→
 95→  const clearAll = useCallback(() => {
 96→    setComments([]);
 97→  }, []);
 98→
 99→  const clearManualComments = useCallback(() => {
100→    setComments((prev) => prev.filter((comment) => comment.source !== "manual"));
101→  }, []);
102→
103→  const replaceSemanticReviewComments = useCallback((nextComments: DiffComment[]) => {
104→    setComments((prev) => applySemanticReviewComments(prev, nextComments));
105→  }, []);
106→
107→  return {
108→    comments,
109→    commentsByLine,
110→    addComment,
111→    updateComment,
112→    deleteComment,
113→    clearAll,
114→    clearManualComments,
115→    replaceSemanticReviewComments,
116→  };
117→}
