 50→pub(crate) fn build_prompt(
 51→    files: &[FileDiff],
 52→    sessions: &[PromptTranscriptSession],
 53→) -> String {
 54→    let mut lines = vec![
 55→        "Review this checkpoint diff semantically.".to_string(),
 56→        "Explain only the important changes, grounded in the diff and transcript context.".to_string(),
 57→        "Comment on lines where the change meaningfully affects behavior, architecture, risk, or reveals non-obvious intent.".to_string(),
 58→        "Skip formatting-only edits, repetitive low-signal edits, and trivial rename churn.".to_string(),
 59→        "Return JSON only with this shape:".to_string(),
 60→        "{\"annotations\":[{\"file_path\":\"src/file.ts\",\"line_number\":12,\"line_kind\":\"add\",\"summary\":\"What this change means.\",\"rationale\":\"Why it was done, especially if transcript context explains it.\",\"importance\":\"high\"}]}".to_string(),
 61→        "Use only line numbers and file paths that exist in the diff below.".to_string(),
 62→        String::new(),
 63→        "## Sanitized checkpoint transcripts".to_string(),
 64→    ];
 65→
 66→    if sessions.is_empty() {
 67→        lines.push("(no transcript context available)".to_string());
 68→    } else {
 69→        for session in sessions {
 70→            lines.push(format!("### Session {}", session.session_index));
 71→            for message in &session.messages {
 72→                lines.push(format!("{}: {}", message.role, message.content));
 73→            }
 74→            lines.push(String::new());
 75→        }
 76→    }
 77→
 78→    lines.push("## Diff".to_string());
 79→    for file in files {
 80→        lines.push(format!("### {} ({})", file.path, file.status));
 81→        for hunk in &file.hunks {
 82→            lines.push(hunk.header.trim().to_string());
 83→            for line in &hunk.lines {
 84→                let line_number = diff_line_number(line);
 85→                lines.push(format!(
 86→                    "L{} {} {}",
 87→                    line_number,
 88→                    diff_line_prefix(&line.kind),
 89→                    line.content.trim_end()
 90→                ));
 91→            }
 92→        }
 93→        lines.push(String::new());
 94→    }
 95→
 96→    lines.join("\n")
 97→}
 98→
 99→pub(crate) fn parse_response_text(
100→    text: &str,
101→) -> Result<Vec<SemanticReviewDraftAnnotation>, String> {
102→    let payload = strip_code_fence(text).trim();
103→    if payload.is_empty() {
104→        return Ok(Vec::new());
105→    }
106→
107→    serde_json::from_str::<SemanticReviewEnvelope>(payload)
108→        .map(|envelope| envelope.annotations)
109→        .map_err(|err| format!("Failed to parse semantic review JSON: {}", err))
110→}
111→
112→pub(crate) fn resolve_annotations(
113→    files: &[FileDiff],
114→    annotations: Vec<SemanticReviewDraftAnnotation>,
115→) -> Vec<SemanticReviewAnnotation> {
116→    let mut resolved = Vec::new();
117→
118→    for annotation in annotations {
119→        let normalized_kind = normalize_line_kind(&annotation.line_kind);
120→        if normalized_kind.is_empty() {
121→            continue;
122→        }
123→
124→        let Some((line_key, line_content)) = find_line(files, &annotation.file_path, annotation.line_number, &normalized_kind) else {
125→            continue;
126→        };
127→
128→        let summary = annotation.summary.trim();
129→        if summary.is_empty() {
130→            continue;
131→        }
132→
133→        let rationale = annotation
134→            .rationale
135→            .map(|value| value.trim().to_string())
136→            .filter(|value| !value.is_empty());
137→        let importance = annotation
138→            .importance
139→            .map(|value| value.trim().to_lowercase())
140→            .filter(|value| !value.is_empty());
141→
142→        resolved.push(SemanticReviewAnnotation {
143→            file_path: annotation.file_path,
144→            line_key,
145→            line_kind: normalized_kind,
146→            line_number: annotation.line_number,
147→            line_content,
148→            summary: summary.to_string(),
149→            rationale,
150→            importance,
151→        });
152→    }
153→
154→    resolved
155→}
156→
157→fn find_line(
158→    files: &[FileDiff],
159→    file_path: &str,
160→    line_number: u32,
161→    line_kind: &str,
162→) -> Option<(String, String)> {
163→    let file = files.iter().find(|file| file.path == file_path)?;
164→    for hunk in &file.hunks {
165→        for line in &hunk.lines {
166→            if line.kind == line_kind && diff_line_number(line) == line_number {
167→                return Some((make_line_key(file_path, line), line.content.clone()));
168→            }
169→        }
170→    }
171→    None
172→}
173→
174→fn make_line_key(file_path: &str, line: &DiffLine) -> String {
175→    format!(
176→        "{}:{}:{}",
177→        file_path,
178→        line.old_lineno.map(|value| value.to_string()).unwrap_or_default(),
179→        line.new_lineno.map(|value| value.to_string()).unwrap_or_default()
180→    )
181→}
182→
183→fn diff_line_number(line: &DiffLine) -> u32 {
184→    if line.kind == "delete" {
185→        line.old_lineno.unwrap_or(0)
186→    } else {
187→        line.new_lineno.or(line.old_lineno).unwrap_or(0)
188→    }
189→}
190→
191→fn diff_line_prefix(kind: &str) -> &'static str {
192→    match kind {
193→        "add" => "+",
194→        "delete" => "-",
195→        _ => " ",
196→    }
197→}
198→
199→fn normalize_line_kind(kind: &str) -> String {
200→    match kind.trim().to_lowercase().as_str() {
201→        "add" | "addition" => "add".to_string(),
202→        "delete" | "deletion" | "remove" | "removed" => "delete".to_string(),
203→        "context" => "context".to_string(),
204→        _ => String::new(),
205→    }
206→}
207→
208→fn strip_code_fence(text: &str) -> &str {
209→    let trimmed = text.trim();
210→    if !trimmed.starts_with("```") {
211→        return trimmed;
212→    }
213→
214→    let without_opening = trimmed
215→        .trim_start_matches("```json")
216→        .trim_start_matches("```")
217→        .trim();
218→    without_opening.strip_suffix("```").unwrap_or(without_opening).trim()
219→}
