 3→export interface DiffComment {
 4→  id: string;
 5→  filePath: string;
 6→  lineKey: string;
 7→  lineKind: "add" | "delete" | "context";
 8→  lineContent: string;
 9→  lineNumber: number;
10→  comment: string;
11→  createdAt: number;
12→  source: DiffCommentSource;
