21→  lineContent: string;
22→  lineNumber: number;
23→  comment: string;
24→}
25→
26→export function createManualDiffComment(
27→  input: CreateDiffCommentInput
28→): DiffComment {
29→  return {
30→    id: crypto.randomUUID(),
31→    ...input,
32→    createdAt: Date.now(),
33→    source: "manual",
34→    readonly: false,
35→  };
36→}
