38→export function applySemanticReviewComments(
39→  comments: DiffComment[],
40→  nextComments: DiffComment[]
41→): DiffComment[] {
42→  return [
43→    ...comments.filter((comment) => comment.source !== "semantic_review"),
44→    ...nextComments,
45→  ];
46→}
