  1→import { useState } from "react";
  2→import { Pencil, Trash2, X } from "lucide-react";
  3→import type { DiffComment } from "../../hooks/use-diff-comments";
  4→
  5→interface DiffCommentBoxProps {
  6→  comments: DiffComment[];
  7→  commentsEnabled: boolean;
  8→  filePath: string;
  9→  lineKey: string;
 10→  lineKind: "add" | "delete" | "context";
 11→  lineContent: string;
 12→  lineNumber: number;
 13→  onSave: (
 14→    filePath: string,
 15→    lineKey: string,
 16→    lineKind: "add" | "delete" | "context",
 17→    lineContent: string,
 18→    lineNumber: number,
 19→    comment: string
 20→  ) => void;
 21→  onUpdate: (id: string, comment: string) => void;
 22→  onDelete: (id: string) => void;
 23→  onClose: () => void;
 24→}
 25→
 26→export function DiffCommentBox({
 27→  comments,
 28→  commentsEnabled,
 29→  filePath,
 30→  lineKey,
 31→  lineKind,
 32→  lineContent,
 33→  lineNumber,
 34→  onSave,
 35→  onUpdate,
 36→  onDelete,
 37→  onClose,
 38→}: DiffCommentBoxProps) {
 39→  const [draft, setDraft] = useState("");
 40→  const [editingId, setEditingId] = useState<string | null>(null);
 41→  const [editDraft, setEditDraft] = useState("");
 42→
 43→  const showNewInput = commentsEnabled && editingId === null;
 44→
 45→  function handleSaveNew() {
 46→    const trimmed = draft.trim();
 47→    if (!trimmed) return;
 48→    onSave(filePath, lineKey, lineKind, lineContent, lineNumber, trimmed);
 49→    setDraft("");
 50→  }
 51→
 52→  function handleStartEdit(c: DiffComment) {
 53→    setEditingId(c.id);
 54→    setEditDraft(c.comment);
 55→  }
 56→
 57→  function handleSaveEdit() {
 58→    if (!editingId) return;
 59→    const trimmed = editDraft.trim();
 60→    if (!trimmed) return;
 61→    onUpdate(editingId, trimmed);
 62→    setEditingId(null);
 63→    setEditDraft("");
 64→  }
 65→
 66→  function handleCancelEdit() {
 67→    setEditingId(null);
 68→    setEditDraft("");
 69→  }
 70→
 71→  return (
 72→    <div
 73→      className="border-y px-3 py-2"
 74→      style={{
 75→        borderColor: "var(--color-accent)",
 76→        backgroundColor: "color-mix(in srgb, var(--color-accent) 6%, var(--color-bg))",
 77→      }}
 78→    >
 79→      {/* Existing comments */}
 80→      {comments.map((c) => (
 81→        <div key={c.id} className="mb-2">
 82→          {editingId === c.id ? (
 83→            <div className="flex flex-col gap-1.5">
 84→              <textarea
 85→                autoFocus
 86→                value={editDraft}
 87→                onChange={(e) => setEditDraft(e.target.value)}
 88→                onKeyDown={(e) => {
 89→                  if (e.key === "Enter" && (e.metaKey || e.ctrlKey)) handleSaveEdit();
 90→                  if (e.key === "Escape") handleCancelEdit();
 91→                }}
 92→                rows={2}
 93→                className="w-full resize-none rounded border border-accent bg-bg px-2 py-1.5 font-mono text-xs text-fg outline-none focus:ring-1 focus:ring-accent"
 94→                placeholder="Edit comment…"
 95→              />
 96→              <div className="flex gap-1.5">
 97→                <button
 98→                  onClick={handleSaveEdit}
 99→                  className="rounded bg-accent px-2.5 py-1 text-[11px] font-medium text-white transition-colors hover:opacity-90"
100→                >
101→                  Save
102→                </button>
103→                <button
104→                  onClick={handleCancelEdit}
105→                  className="rounded px-2.5 py-1 text-[11px] text-fg-subtle transition-colors hover:text-fg"
106→                >
107→                  Cancel
108→                </button>
109→              </div>
110→            </div>
111→          ) : (
112→            <div className="group flex items-start gap-2">
113→              <div
114→                className="mt-0.5 h-2 w-2 shrink-0 rounded-full"
115→                style={{ backgroundColor: "var(--color-accent)" }}
116→              />
117→              <div className="min-w-0 flex-1">
118→                {c.source === "semantic_review" && (
119→                  <span className="mb-1 inline-flex rounded-full bg-accent-bg px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wider text-accent-fg">
120→                    Semantic review
121→                  </span>
122→                )}
123→                <p className="text-xs text-fg-muted whitespace-pre-wrap">{c.comment}</p>
124→              </div>
125→              {!c.readonly && (
126→                <div className="flex shrink-0 gap-1 opacity-0 transition-opacity group-hover:opacity-100">
127→                  <button
128→                    onClick={() => handleStartEdit(c)}
129→                    className="rounded p-0.5 text-fg-subtle hover:text-accent-fg"
130→                    title="Edit"
131→                  >
132→                    <Pencil size={11} />
133→                  </button>
134→                  <button
135→                    onClick={() => onDelete(c.id)}
136→                    className="rounded p-0.5 text-fg-subtle hover:text-red"
137→                    title="Delete"
138→                  >
139→                    <Trash2 size={11} />
140→                  </button>
141→                </div>
142→              )}
143→            </div>
144→          )}
145→        </div>
146→      ))}
147→
148→      {/* New comment input */}
149→      {showNewInput && editingId === null && (
150→        <div className="flex flex-col gap-1.5">
151→          <textarea
152→            autoFocus
153→            value={draft}
154→            onChange={(e) => setDraft(e.target.value)}
155→            onKeyDown={(e) => {
156→              if (e.key === "Enter" && (e.metaKey || e.ctrlKey)) handleSaveNew();
157→              if (e.key === "Escape") onClose();
158→            }}
159→            rows={2}
160→            className="w-full resize-none rounded border border-border-subtle bg-bg px-2 py-1.5 font-mono text-xs text-fg outline-none focus:border-accent focus:ring-1 focus:ring-accent"
161→            placeholder="Add a review comment… (⌘↵ to save)"
162→          />
163→          <div className="flex gap-1.5">
164→            <button
165→              onClick={handleSaveNew}
166→              disabled={!draft.trim()}
167→              className="rounded bg-accent px-2.5 py-1 text-[11px] font-medium text-white transition-colors hover:opacity-90 disabled:opacity-40"
168→            >
169→              Save
170→            </button>
171→            <button
172→              onClick={onClose}
173→              className="flex items-center gap-1 rounded px-2.5 py-1 text-[11px] text-fg-subtle transition-colors hover:text-fg"
174→            >
175→              <X size={10} />
176→              Cancel
177→            </button>
178→          </div>
179→        </div>
180→      )}
181→    </div>
182→  );
183→}
