468→                }}
469→                disabled={semanticReviewMutation.isPending}
470→                className="flex items-center gap-1.5 rounded border border-border-subtle px-2.5 py-1 text-[11px] text-fg-subtle transition-colors hover:border-accent hover:text-fg disabled:cursor-not-allowed disabled:opacity-50"
471→              >
