pub struct AnthropicRequest {
    pub model: String,
    pub max_tokens: u32,
    pub temperature: f32,
    pub system: String,
    pub messages: Vec<AnthropicMessage>,
}

#[derive(serde::Serialize)]
pub struct AnthropicMessage {
    pub role: String,
    pub content: String,
}

#[derive(serde::Deserialize)]
pub struct AnthropicResponse {
    pub content: Vec<AnthropicContentBlock>,
}

