#[cfg_attr(mobile, tauri::mobile_entry_point)]
pub fn run() {
    tauri::Builder::default()
        .plugin(tauri_plugin_opener::init())
        .plugin(tauri_plugin_dialog::init())
        .plugin(tauri_plugin_window_state::Builder::default().build())
        .manage(Mutex::new(AppState {
            watched_repos: HashSet::new(),
        }))
        .manage(Mutex::new(ghostty::GhosttyState::new()))
        .setup(|app| {
            // Start the ghostty tick loop on the MAIN THREAD via a Cocoa timer.
            // ghostty_app_tick processes Cocoa/Metal events and must run on the
            // main thread.
            {
                use block2::RcBlock;
                use objc2_foundation::NSTimer;

                let handle = app.handle().clone();
                let tick_block = RcBlock::new(move |_timer| {
                    let state = handle.state::<Mutex<ghostty::GhosttyState>>();
                    let mutex = state.inner();
                    if let Ok(gs) = mutex.lock() {
                        if let Some(app) = gs.app.as_ref() {
                            app.tick();
                        }
                    }
                });

                let _tick_timer = unsafe {
                    NSTimer::scheduledTimerWithTimeInterval_repeats_block(
                        1.0 / 60.0,
                        true,
                        &tick_block,
                    )
                };
            }

            // System tray
            use tauri::menu::{MenuBuilder, MenuItemBuilder};
            use tauri::tray::TrayIconBuilder;
            use tauri::Manager;

            let show = MenuItemBuilder::with_id("show", "Show Entire").build(app)?;
            let quit = MenuItemBuilder::with_id("quit", "Quit").build(app)?;
            let menu = MenuBuilder::new(app)
                .item(&show)
                .separator()
                .item(&quit)
                .build()?;

            let _tray = TrayIconBuilder::new()
                .tooltip("Entire Desktop")
                .menu(&menu)
                .on_menu_event(move |app, event| {
                    match event.id().as_ref() {
                        "show" => {
                            if let Some(window) = app.get_webview_window("main") {
                                let _ = window.show();
                                let _ = window.set_focus();
                            }
                        }
                        "quit" => {
                            app.exit(0);
                        }
                        _ => {}
                    }
                })
                .on_tray_icon_event(|tray, event| {
                    if let tauri::tray::TrayIconEvent::Click { .. } = event {
                        let app = tray.app_handle();
                        if let Some(window) = app.get_webview_window("main") {
                            let _ = window.show();
                            let _ = window.set_focus();
                        }
                    }
                })
                .build(app)?;

            Ok(())
        })
        .invoke_handler(tauri::generate_handler![
            debug_log,
            list_repos,
            register_repo,
            unregister_repo,
            block_repo,
            get_app_settings,
            save_app_settings,
            create_worktree,
            delete_worktree,
            delete_branch,
            list_checkpoints,
            get_transcript,
            get_checkpoint_diff,
            run_checkpoint_semantic_review,
            get_branch_diff,
            list_sessions,
            get_entire_settings,
            get_entire_logs,
            get_checkpoint_logs,
            get_raw_checkpoint_metadata,
            get_raw_session_file,
            launch_ghostty_agent,
            list_trails,
            watch_repo,
            ghostty::commands::ghostty_create_surface,
            ghostty::commands::ghostty_destroy_surface,
            ghostty::commands::ghostty_update_overlay,
            ghostty::commands::ghostty_show_overlay,
            ghostty::commands::ghostty_focus_overlay,
            ghostty::commands::ghostty_send_text,
            list_journal_entries,
            get_journal_entry,
            generate_journal_entry,
            get_journal_dates,
        ])
        .run(tauri::generate_context!())
        .expect("error while running tauri application");
}

