    let files = if let Some(sha) = commit_sha.filter(|s| !s.is_empty()) {
        collect_checkpoint_diff(&repo, &sha)?
    } else if let Some(branch_name) = branch.filter(|b| !b.is_empty()) {
        collect_branch_diff(&repo, &branch_name)?
    } else {
        return Err("Either commit_sha or branch must be provided".to_string());
    };

    if files.is_empty() {
        return Ok(bugbot_review::RunBugbotReviewResponse {
            review_run_id: generate_review_run_id(),
            annotations: Vec::new(),
        });
    }

    let prompt = bugbot_review::build_prompt(&files);
    let raw_text = call_anthropic_review(
        &prompt,
        "You are a senior engineer reviewing code for bugs, security vulnerabilities, and concrete risks. Return JSON only with precise, line-linked findings.",
        4_000,
        0.1,
    )?;
    let parsed = semantic_review::parse_response_text(&raw_text)?;
    let annotations = semantic_review::resolve_annotations(&files, parsed);

    Ok(bugbot_review::RunBugbotReviewResponse {
        review_run_id: generate_review_run_id(),
        annotations,
    })
}

