    let diff = repo
        .diff_tree_to_tree(Some(&base_tree), Some(&branch_tree), None)
        .map_err(|e| format!("Failed to compute branch diff: {}", e))?;

    collect_diff_files(&diff)
}

#[tauri::command]
fn run_bugbot_review(
    repo_path: String,
    commit_sha: Option<String>,
    branch: Option<String>,
) -> Result<bugbot_review::RunBugbotReviewResponse, String> {
    let repo = git::open_repo(&repo_path)?;

    let files = if let Some(sha) = commit_sha.filter(|s| !s.is_empty()) {
        collect_checkpoint_diff(&repo, &sha)?
    } else if let Some(branch_name) = branch.filter(|b| !b.is_empty()) {
        collect_branch_diff(&repo, &branch_name)?
    } else {
        return Err("Either commit_sha or branch must be provided".to_string());
    };

    if files.is_empty() {
        return Ok(bugbot_review::RunBugbotReviewResponse {
            review_run_id: generate_review_run_id(),
            annotations: Vec::new(),
        });
    }

    let prompt = bugbot_review::build_prompt(&files);
    let raw_text = call_anthropic_review(
        &prompt,
        "You are a senior engineer reviewing code for bugs, security vulnerabilities, and concrete risks. Return JSON only with precise, line-linked findings.",
        4_000,
        0.1,
    )?;
    let parsed = semantic_review::parse_response_text(&raw_text)?;
    let annotations = semantic_review::resolve_annotations(&files, parsed);

    Ok(bugbot_review::RunBugbotReviewResponse {
        review_run_id: generate_review_run_id(),
        annotations,
    })
}

#[tauri::command]
fn watch_repo(
    repo_path: String,
    app: tauri::AppHandle,
    state: State<'_, Mutex<AppState>>,
) -> Result<(), String> {
    let mut app_state = state.lock().map_err(|_| "State lock error".to_string())?;

    // Don't double-watch
    if app_state.watched_repos.contains(&repo_path) {
        return Ok(());
    }
    app_state.watched_repos.insert(repo_path.clone());

    let app_handle = app.clone();
    let repo_path_for_closure = repo_path.clone();
    watcher::watch_repo(&repo_path, move |event| {
        let event_name = match event {
            watcher::WatchEvent::CheckpointChanged => "checkpoint-changed",
            watcher::WatchEvent::SessionChanged(_) => "session-changed",
            watcher::WatchEvent::ConfigChanged => "config-changed",
        };
        let _ = app_handle.emit(event_name, serde_json::json!({
            "repoPath": repo_path_for_closure,
        }));
    })?;

    Ok(())
}

